/*eslint-disable */;
; (function ($, window, documnet, undefined) {
    console.log('TDS PinkingShare Plugin v1.5 (30-07) [1.4]')
    // Create the defaults once
    var pluginName = "polygonPluggin",
        defaults = {
            propertyName: "value",
            clip: 20,
            pinkingShare: false,//pinkinghare default false:
            dropShadow: false, // drop shadow default false:
            foldedShadow: false, //folded shadow default false:
            dropShadowColor: '4px 4px 3px rgba(0,0,0, 0.3)',
        };
    var x1, y1, x2, y2, x3, y3;

    // The actual plugin constructor
    function Plugin(element, options) {
        this.element = element;
        this.options = $.extend({}, defaults, options);
        this._defaults = defaults;
        this._name = pluginName;
        var that = this.element;
        this.init(this, that);
    }

    Plugin.prototype = {

        init: function (that, that2) {
            that.options['clip'] = parseInt(that.options['clip']);
            imgWidth = parseFloat(that2.style.width) + parseFloat(that2.style.width);
            imgHeight = parseFloat(that2.style.height) + parseFloat(that2.style.height);
            /*x1 = 0;
            y1 = (that.options['clip']) / 2;
            x2 = that.options['clip'] / 2;
            y2 = 0;
            x3 = that.options['clip'];
            y3 = (that.options['clip']) / 2;*/
            this._doClip(that, that2, imgWidth, imgHeight);
            return this;
        },

        _doClip: function (that, that2, imgWidth, imgHeight) {
            var txt = '';
            var remainder = imgHeight % that.options['clip'];
            var division = imgHeight / that.options['clip'];
            var remaning = remainder / parseInt(division);
            that.options['clipHeight'] = that.options['clip'] + remaning;

            var remainder = imgWidth % that.options['clip'];
            var division = imgWidth / that.options['clip'];
            var remaning = remainder / parseInt(division);
            that.options['clipWidth'] = that.options['clip'] + remaning;

            //  console.log(that.options['clipWidth']);
            //  console.log(that.options['clipHeight']);
            // that.options['clipWidth'] = (that.options['clipWidth']).toFixed(2);
            // that.options['clipHeight'] = (that.options['clipHeight']).toFixed(2);

            x1 = (that.options['clipHeight']) / 2;
            y1 = imgHeight;
            x2 = 0;
            y2 = imgHeight - ((that.options['clipHeight']) / 2);
            x3 = (that.options['clipHeight']) / 2;
            y3 = imgHeight - that.options['clipHeight'];

            while (y3 >= -1) {
                txt += "" + (x1.toFixed(2)) + "px " + (y1.toFixed(2)) + "px ," + (x2.toFixed(2)) + "px " + (y2.toFixed(2)) + "px ," + (x3.toFixed(2)) + "px " + (y3.toFixed(2)) + "px ,";
                if (((y3.toFixed(2) - that.options['clipHeight'].toFixed(2)) <= -1)) {
                    break;
                } else {
                    y1 = y3;
                    y2 = y2 - that.options['clipHeight'];
                    y3 = y1 - that.options['clipHeight'];
                }
            }
            //console.log(x1,y1);
            //  console.log(x2,y2);
            // console.log(x3,y3);

            x1 = x2;
            y1 = y2;
            x2 = x3;
            y2 = y3;
            x3 = x1 + that.options['clipWidth'];
            y3 = y1;

            while (imgWidth.toFixed(2) - (x3.toFixed(2)) >= 0) {
                if (!$(that2).hasClass('right_triangle'))
                    txt += "" + (x1.toFixed(2)) + "px " + (y1.toFixed(2)) + "px ," + (x2.toFixed(2)) + "px " + (y2.toFixed(2)) + "px ," + (x3.toFixed(2)) + "px " + (y3.toFixed(2)) + "px ,";
                if (x3 > imgWidth || parseFloat(that.options['clipWidth'] + x3).toFixed(2) > parseFloat(imgWidth.toFixed(2))) {
                    break;
                } else {
                    x1 = x3;
                    y1 = y3;
                    x2 = x3 + (that.options['clipWidth'] / 2);
                    y2 = y2;
                    x3 = x1 + that.options['clipWidth'];
                    y3 = y1;
                }
            }


            x1 = x2;
            y1 = y2;
            x2 = x3;
            y2 = y3;
            x3 = x1;
            y3 = y1 + that.options['clipHeight'];

            while (y3 < imgHeight) {
                if ((y3 + that.options['clipHeight']) > imgHeight || (y3 + (that.options['clipHeight'] / 2)) > imgHeight) {
                    break;
                } else {
                    if (!$(that2).hasClass('right_triangle'))
                        txt += "" + (x1.toFixed(2)) + "px " + (y1.toFixed(2)) + "px ," + (x2.toFixed(2)) + "px " + (y2.toFixed(2)) + "px ," + (x3.toFixed(2)) + "px " + (y3.toFixed(2)) + "px ,";
                    y1 = y3;
                    y2 = (y3 + (that.options['clipHeight'] / 2));
                    y3 = y3 + that.options['clipHeight'];
                }
            }

            x1 = x2;
            y1 = y2;
            x2 = x3;
            y2 = y3;
            x3 = x1 - that.options['clipWidth'];
            y3 = y1;
            txt += "" + (x1.toFixed(2)) + "px " + (y1.toFixed(2)) + "px ," + (x2.toFixed(2)) + "px " + (y2.toFixed(2)) + "px ,";
            while (x3 >= -1) {
                if (!that.options['foldedShadow']) {
                    txt += "" + (x1.toFixed(2)) + "px " + (y1.toFixed(2)) + "px ," + (x2.toFixed(2)) + "px " + (y2.toFixed(2)) + "px ," + (x3.toFixed(2)) + "px " + (y3.toFixed(2)) + "px ,";
                }
                if ((x3 - (that.options['clipWidth'] / 2) < 0 || x3 - that.options['clipWidth'] < 0)) {
                    break;
                } else {
                    x1 = x3;
                    x2 = (x3 - (that.options['clipWidth'] / 2));
                    x3 = x3 - that.options['clipWidth'];
                }
            }


            txt = txt.slice(0, -1);

            if (that.options['pinkingShare']) {
                // alert("pinkinshare")
                $(that2).css("clip-path", "polygon(" + txt + ")");

            } else {

                $(that2).css("clip-path", " ");
            }

            if (that.options['dropShadow']) {
                if (!$(that2).parent().hasClass('newDiv')) {
                    var top = $(that2).css('top');
                    var left = $(that2).css('left');
                    $(that2).wrap("<div class='newDiv' style='position:absolute;top:" + top + ";left:" + left + ";width:" + (imgWidth) + "px;height:" + (imgHeight / 3) + "px;filter: drop-shadow(" + that.options['dropShadowColor'] + ");'></div>");
                    $(that2).css('top', '0px');
                    $(that2).css('left', '0px');

                } else {
                    $(that2).parent().css('filter', 'drop-shadow(' + that.options['dropShadowColor'] + ')');
                }
            } else {
                if (!$(that2).parent().hasClass('newDiv')) {
                    var top = $(that2).css('top') + 10; //tanmay chamge
                    var left = $(that2).css('left') + 10; //tanmay change

                    $(that2).wrap("<div class='newDiv' style='position:absolute;top:" + top + ";left:" + left + ";width:" + (imgWidth) + "px;height:" + (imgHeight / 3) + "px; '></div>");

                    $(that2).css('top', '0px') + 10; //tanmay change
                    $(that2).css('left', '0px') + 10; //tanmay change

                } else {
                    $(that2).parent().css('filter', '');
                }
            }

            if (that.options['foldedShadow']) {
                if (!that.options['dropShadow']) {
                    $(that2).parent().css('filter', 'drop-shadow(0px 0px 1px rgba(71, 69, 69, 0.5))');
                }
                var width = imgWidth;
                if (that.options['pinkingShare'])
                    width = imgWidth - 20;

                // $(that2).parent().append("<div class='gradUp' style=';filter: blur(2px);bottom:0px;z-index: 9999;position: absolute;margin-left: 0px;width:" + (width) + "px;height: 30px;background-image: linear-gradient(to top, rgba(0,0,0,0.3), rgba(0,0,0,0));'></div>");
                // $(that2).parent().append("<div class='gradDown' style='filter: blur(2px);bottom:-20px;z-index: 9999;position: absolute;margin-left: 0px;width:" + (width) + "px;height: 30px;background-image: linear-gradient(to top, rgba(0,0,0,0), rgba(0,0,0,0.3));'></div>");
                //Vijay changes on 6feb
                // $(that2).parent().siblings().append("<div class='gradUp' style=';filter: blur(2px);bottom:0px;z-index: 9999;position: absolute;margin-left: 0px;width:" + (width) + "px;height: 30px;background-image: linear-gradient(to top, rgba(0,0,0,0.3), rgba(0,0,0,0));'></div>");
                // $(that2).parent().siblings().append("<div class='gradDown' style='filter: blur(2px);bottom:-20px;z-index: 9999;position: absolute;margin-left: 0px;width:" + (width) + "px;height: 30px;background-image: linear-gradient(to top, rgba(0,0,0,0), rgba(0,0,0,0.3));'></div>");
                $(that2).parent().children().append("<div class='gradUp' style=';filter: blur(1px);bottom:0px;z-index: 9999;position: absolute;margin-left: 0px;width:" + (width) + "px;height: 30px;overflow: hidden !important;background-image: linear-gradient(to top, rgba(0,0,0,0.1), rgba(0,0,0,0));'></div>"); //tanmay change
                $(that2).parent().children().append("<div class='gradDown' style='filter: blur(1px);bottom:-20px;z-index: 9999;position: absolute;margin-left: 0px;width:" + (width) + "px;height: 30px;overflow: hidden !important;background-image: linear-gradient(to top, rgba(0,0,0,0), rgba(0,0,0,0.1));'></div>"); //tanmay change s




            }
        },

        doClip: function (clipWidth, pinkingShare, dropShadow, foldedShadow) {
            var that = this;
            $('.' + this.element.className).each(function () {
                that.options['clip'] = (clipWidth != undefined ? clipWidth : this.options['clip']);
                that.options['pinkingShare'] = (pinkingShare != undefined ? pinkingShare : this.options['pinkingShare']);
                that.options['dropShadow'] = (dropShadow != undefined ? dropShadow : this.options['dropShadow']);
                that.options['foldedShadow'] = (foldedShadow != undefined ? foldedShadow : this.options['foldedShadow']);
                that.init(that, this);
            });
        }
    };

    $.fn[pluginName] = function (options) {
        return this.each(function () {
            if ($.data(this, "plugin_" + pluginName) == undefined) {
                return $.data(this, "plugin_" + pluginName,
                    new Plugin(this, options));
            }
        }).data('plugin_' + pluginName);
    };

})(jQuery, window, document);